    33→public class AsyncCommitManager extends AbstractCommitManager {
    34→    private static final Logger LOG = LoggerFactory.getLogger(AsyncCommitManager.class);
    35→    private final Consumer<?, ?> consumer;
    36→
    37→    private final OffsetCache offsetCache = new OffsetCache();
