    40→    public AsyncCommitManager(Consumer<?, ?> consumer, KafkaConsumer kafkaConsumer, String threadId, String printableTopic) {
    41→        super(consumer, kafkaConsumer, threadId, printableTopic);
    42→
    43→        this.consumer = consumer;
    44→
    45→        offsetRepository = configuration.getOffsetRepository();
    46→    }
