    50→        if (kafkaConsumer.getEndpoint().getConfiguration().isAutoCommitEnable()) {
    51→            LOG.info("Auto commitAsync {} from {}", threadId, printableTopic);
    52→            consumer.commitAsync();
    53→        }
    54→    }
    55→
    56→    @Override
    57→    public void commit(TopicPartition partition) {
    58→        Long offset = offsetCache.getOffset(partition);
    59→        if (offset == null) {
    60→            return;
    61→        }
    62→
    63→        commitAsync(consumer, partition, offset);
    64→    }
