    66→    private void commitAsync(Consumer<?, ?> consumer, TopicPartition partition, long partitionLastOffset) {
    67→        if (LOG.isDebugEnabled()) {
    68→            LOG.debug("Auto commitAsync on stop {} from topic {}", threadId, partition.topic());
    69→        }
    70→
    71→        final Map<TopicPartition, OffsetAndMetadata> topicPartitionOffsetAndMetadataMap
    72→                = Collections.singletonMap(partition, new OffsetAndMetadata(partitionLastOffset + 1));
    73→        consumer.commitAsync(topicPartitionOffsetAndMetadataMap, this::postCommitCallback);
    74→    }
