    77→    public KafkaManualCommit getManualCommit(
    78→            Exchange exchange, TopicPartition partition, ConsumerRecord<Object, Object> consumerRecord) {
    79→
    80→        KafkaManualCommitFactory manualCommitFactory = kafkaConsumer.getEndpoint().getKafkaManualCommitFactory();
    81→        if (manualCommitFactory == null) {
    82→            manualCommitFactory = new DefaultKafkaManualAsyncCommitFactory();
    83→        }
    84→
    85→        return getManualCommit(exchange, partition, consumerRecord, manualCommitFactory);
    86→    }
    87→
    88→    @Override
    89→    public void recordOffset(TopicPartition partition, long partitionLastOffset) {
    90→        offsetCache.recordOffset(partition, partitionLastOffset);
    91→    }
    92→
    93→    private void postCommitCallback(Map<TopicPartition, OffsetAndMetadata> committed, Exception exception) {
    94→        if (exception == null) {
    95→            if (offsetRepository != null) {
    96→                for (var entry : committed.entrySet()) {
    97→                    saveStateToOffsetRepository(entry.getKey(), entry.getValue().offset(), offsetRepository);
    98→                }
    99→            }
   100→        }
